import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface WishlistStore {
  wishlist: string[];          // product id 배열
  loading: boolean;
  fetch: () => Promise<void>;  // 로그인 후 Supabase에서 불러오기
  toggle: (productId: string, isLoggedIn: boolean) => Promise<void>;
  isWished: (id: string) => boolean;
  clear: () => void;
}

export const useWishlistStore = create<WishlistStore>()(
  persist(
    (set, get) => ({
      wishlist: [],
      loading: false,

      fetch: async () => {
        set({ loading: true });
        try {
          const res = await fetch('/api/wishlist');
          if (!res.ok) throw new Error();
          const { wishlist } = await res.json();
          // 로컬 + 서버 합집합으로 머지
          const merged = Array.from(new Set([...get().wishlist, ...wishlist]));
          set({ wishlist: merged });
        } catch {
          // 비로그인 or 오류 시 로컬 유지
        } finally {
          set({ loading: false });
        }
      },

      toggle: async (productId, isLoggedIn) => {
        const { wishlist } = get();
        const wished = wishlist.includes(productId);

        // 낙관적 업데이트 (즉시 UI 반영)
        set({
          wishlist: wished
            ? wishlist.filter((id) => id !== productId)
            : [...wishlist, productId],
        });

        if (!isLoggedIn) return; // 비로그인은 로컬만

        try {
          const res = await fetch('/api/wishlist', {
            method: wished ? 'DELETE' : 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ product_id: productId }),
          });
          if (!res.ok) throw new Error();
        } catch {
          // 실패 시 롤백
          set({ wishlist });
        }
      },

      isWished: (id) => get().wishlist.includes(id),

      clear: () => set({ wishlist: [] }),
    }),
    {
      name: 'kitpick-wishlist', // localStorage에 자동 저장
    }
  )
);
